+        let mut chunks = Vec::new();
+        let mut offset = 0usize;
+        let mut idx = 0usize;
+        while offset < input.len() {
+            let size = chunk_sizes[idx % chunk_sizes.len()].max(1);
+            let end = (offset + size).min(input.len());
+            chunks.push(input[offset..end].to_vec());
+            offset = end;
